// Erişim kalıbı analizi
const logs = $input.all();
const logData = logs.map(l => l.json);

// Anomali tespiti
const anomalyRules = [
  {
    name: 'OFF_HOURS_ACCESS',
    check: (log) => log.time_category === 'OFF_HOURS' && ['DELETE', 'EXPORT', 'ADMIN'].includes(log.action),
    severity: 'HIGH',
    message: 'Mesai dışı hassas işlem'
  },
  {
    name: 'FAILED_LOGIN_BURST',
    check: (log) => log.action === 'LOGIN_FAILED',
    severity: 'MEDIUM'
  },
  {
    name: 'BULK_EXPORT',
    check: (log) => log.action === 'EXPORT' && log.resource === 'users',
    severity: 'HIGH',
    message: 'Toplu kullanıcı export'
  },
  {
    name: 'SENSITIVE_ACCESS',
    check: (log) => log.action === 'READ' && log.resource.includes('payment'),
    severity: 'MEDIUM'
  }
];

const anomalies = [];
const failedLogins = {};

logData.forEach(log => {
  anomalyRules.forEach(rule => {
    if (rule.check(log)) {
      anomalies.push({
        userId: log.user_id,
        email: log.email,
        role: log.role,
        anomalyType: rule.name,
        severity: rule.severity,
        message: rule.message || `${rule.name} tespit edildi`,
        timestamp: log.timestamp,
        ipAddress: log.ip_address,
        action: log.action,
        resource: log.resource
      });
    }
  });

  if (log.action === 'LOGIN_FAILED') {
    failedLogins[log.user_id] = (failedLogins[log.user_id] || 0) + 1;
  }
});

// Fazla başarısız giriş kontrolü
Object.keys(failedLogins).forEach(userId => {
  if (failedLogins[userId] >= 5) {
    const userLogs = logData.filter(l => l.user_id === userId);
    anomalies.push({
      userId,
      email: userLogs[0]?.email,
      role: userLogs[0]?.role,
      anomalyType: 'EXCESSIVE_FAILED_LOGINS',
      severity: 'CRITICAL',
      message: `${failedLogins[userId]} başarısız giriş denemesi`,
      failedAttempts: failedLogins[userId],
      action: 'LOCK_ACCOUNT'
    });
  }
});

if (anomalies.length === 0) {
  return [{ json: { message: 'No anomalies detected', totalLogs: logData.length } }];
}

return anomalies.map(a => ({ json: a }));
